// src/App.jsx - CÓDIGO DE TESTE MÍNIMO
import React from 'react';
import { MapContainer, TileLayer } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';

const App = () => {
  return (
    <div style={{ height: '100vh', padding: '1rem' }}>
      <h1>🚗 TESTE: Se vê isso, o React funciona!</h1>
      
      <div style={{ height: '500px', border: '3px solid #FFC107', borderRadius: '8px' }}>
        <MapContainer 
          center={[-23.963214, -46.28054]} 
          zoom={13} 
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; OpenStreetMap'
          />
        </MapContainer>
      </div>
      
      <p style={{ marginTop: '1rem' }}>
        ✅ Leaflet está funcionando! Agora é só integrar com os dados.
      </p>
    </div>
  );
};

export default App;
